def expand_polynomial(s):
    from collections import defaultdict
    import re

    def binomial_coefficient(n, k):
        if k == 0 or k == n:
            return 1
        k = min(k, n - k)
        c = 1
        for i in range(k):
            c = c * (n - i) // (i + 1)
        return c

    parts = re.match(r'\(x \+ (-?\d+)\)\^(\d+)', s).groups()
    a = int(parts[0])
    n = int(parts[1])

    coefficients = defaultdict(int)

    for k in range(n + 1):
        coeff = binomial_coefficient(n, k) * (a ** k)
        power = n - k
        coefficients[power] += coeff

    terms = []
    for power in sorted(coefficients.keys(), reverse=True):
        coeff = coefficients[power]
        if coeff == 0:
            continue
        if coeff > 0 and terms:
            terms.append('+')
        if abs(coeff) != 1 or power == 0:
            terms.append(str(abs(coeff)))
        if power > 1:
            terms.append('x^' + str(power))
        elif power == 1:
            terms.append('x')

    return ' '.join(terms) if terms else '0'
